import{_ as a,o as e,c as d,ae as i}from"./chunks/framework.BMMOQqto.js";const u=JSON.parse('{"title":"Q8: 如何保证微服务高可用？限流/熔断方案？","description":"","frontmatter":{},"headers":[],"relativePath":"02-microservice/q8-high-availability.md","filePath":"02-microservice/q8-high-availability.md"}'),r={name:"02-microservice/q8-high-availability.md"};function l(h,t,o,n,s,c){return e(),d("div",null,[...t[0]||(t[0]=[i('<h1 id="q8-如何保证微服务高可用-限流-熔断方案" tabindex="-1">Q8: 如何保证微服务高可用？限流/熔断方案？ <a class="header-anchor" href="#q8-如何保证微服务高可用-限流-熔断方案" aria-label="Permalink to &quot;Q8: 如何保证微服务高可用？限流/熔断方案？&quot;">​</a></h1><h2 id="高可用策略" tabindex="-1">高可用策略 <a class="header-anchor" href="#高可用策略" aria-label="Permalink to &quot;高可用策略&quot;">​</a></h2><table tabindex="0"><thead><tr><th>策略</th><th>作用</th></tr></thead><tbody><tr><td>服务冗余</td><td>多实例部署，负载均衡</td></tr><tr><td>服务降级</td><td>核心功能优先，非核心功能熔断</td></tr><tr><td>限流</td><td>控制QPS，防止系统过载</td></tr><tr><td>熔断</td><td>快速失败，防止故障蔓延</td></tr><tr><td>隔离</td><td>线程池隔离、信号量隔离</td></tr><tr><td>超时重试</td><td>设置合理的超时和重试</td></tr><tr><td>幂等</td><td>接口幂等设计，防止重复请求</td></tr><tr><td>多级缓存</td><td>本地缓存+Redis，减少后端压力</td></tr></tbody></table><h2 id="限流算法" tabindex="-1">限流算法 <a class="header-anchor" href="#限流算法" aria-label="Permalink to &quot;限流算法&quot;">​</a></h2><h3 id="_1-计数器算法" tabindex="-1">① 计数器算法 <a class="header-anchor" href="#_1-计数器算法" aria-label="Permalink to &quot;① 计数器算法&quot;">​</a></h3><ul><li>维护一个计数器，每请求+1</li><li>优点：简单</li><li>缺点：无法应对突发流量</li></ul><h3 id="_2-滑动窗口" tabindex="-1">② 滑动窗口 <a class="header-anchor" href="#_2-滑动窗口" aria-label="Permalink to &quot;② 滑动窗口&quot;">​</a></h3><ul><li>将时间窗口分成多个小窗口</li><li>优点：比计数器平滑</li></ul><h3 id="_3-漏桶算法" tabindex="-1">③ 漏桶算法 <a class="header-anchor" href="#_3-漏桶算法" aria-label="Permalink to &quot;③ 漏桶算法&quot;">​</a></h3><ul><li>以固定速率处理请求</li><li>优点：请求均匀</li><li>缺点：突发请求需要等待</li></ul><h3 id="_4-令牌桶算法" tabindex="-1">④ 令牌桶算法 <a class="header-anchor" href="#_4-令牌桶算法" aria-label="Permalink to &quot;④ 令牌桶算法&quot;">​</a></h3><ul><li>以固定速率生成令牌，请求获取令牌</li><li>优点：允许突发流量</li></ul><h2 id="sentinel熔断策略" tabindex="-1">Sentinel熔断策略 <a class="header-anchor" href="#sentinel熔断策略" aria-label="Permalink to &quot;Sentinel熔断策略&quot;">​</a></h2><table tabindex="0"><thead><tr><th>策略</th><th>触发条件</th><th>效果</th></tr></thead><tbody><tr><td>慢调用比例</td><td>响应时间 &gt; 阈值，且比例 &gt; 比例阈值</td><td>熔断</td></tr><tr><td>异常比例</td><td>异常比例 &gt; 阈值</td><td>熔断</td></tr><tr><td>异常数</td><td>异常数量 &gt; 阈值</td><td>熔断</td></tr></tbody></table>',14)])])}const _=a(r,[["render",l]]);export{u as __pageData,_ as default};
